    int timeout_seconds_;

public:
    Session(const std::string& user_id, int timeout_seconds = 3600)
        : user_id_(user_id), 
          created_time_(std::chrono::steady_clock::now()),
          timeout_seconds_(timeout_seconds) {}

    const std::string& get_user_id() const { return user_id_; }
    bool is_expired() const {
        auto now = std::chrono::steady_clock::now();
        auto duration = std::chrono::duration_cast<std::chrono::seconds>(now - created_time_).count();
        return duration > timeout_seconds_;
    }
