    void remove_session(const std::string& user_id) {
        auto it = std::remove_if(sessions_.begin(), sessions_.end(),
            [&user_id](Session* session) {
                bool should_remove = session && session->get_user_id() == user_id;
                if (should_remove) {
                    delete session;
                }
                return should_remove;
            });
        sessions_.erase(it, sessions_.end());
    }

